import { ImageResponse } from 'next/og';
import { NextRequest } from 'next/server';

export const runtime = 'edge';

// Branding overlay embedded as base64 — RGBA PNG, Satori compatible, zero network requests
const OVERLAY_B64 = 'data:image/png;base64,';

export async function GET(req: NextRequest) {
    try {
        const { searchParams } = new URL(req.url);
        const imageUrl = searchParams.get('image');
        const defaultImage = 'https://images.unsplash.com/photo-1546422904-90eab23c3d7e?q=80&w=1200&auto=format&fit=crop';
        const targetImage = imageUrl || defaultImage;

        return new ImageResponse(
            (
                <div
                    style={{
                        height: '100%',
                        width: '100%',
                        display: 'flex',
                        position: 'relative',
                        backgroundColor: '#fff',
                    }}
                >
                    {/* Background: Article Featured Photo */}
                    <img
                        src={targetImage}
                        style={{
                            position: 'absolute',
                            top: 0,
                            left: 0,
                            width: '100%',
                            height: '100%',
                            objectFit: 'cover',
                        }}
                    />
                    {/* Branding Overlay — RGBA, always rendered, no network needed */}
                    <img
                        src={OVERLAY_B64}
                        style={{
                            position: 'absolute',
                            top: 0,
                            left: 0,
                            width: '100%',
                            height: '100%',
                        }}
                    />
                </div>
            ),
            { width: 1200, height: 630 }
        );
    } catch (e: any) {
        console.error(e.message);
        return new Response('Failed to generate image', { status: 500 });
    }
}
